import { useState } from "react";
import "./index.css";
import ConnectionScreen from "./components/ConnectionScreen";
import InputForm from "./components/InputForm";
import DashboardScreen from "./components/DashboardScreen";
import axios from "axios";

const BASE = "http://localhost:8000";

const connectDatabase    = async (cs) => (await axios.post(`${BASE}/api/connection/connect`, { connection_string: cs })).data;
const generateDashboard  = async (p)  => (await axios.post(`${BASE}/api/dashboard/generate`, p)).data;

export default function App() {
  const [screen,      setScreen]      = useState("connect");
  const [connData,    setConnData]    = useState(null);
  const [dashData,    setDashData]    = useState(null);
  const [colorSchema, setColorSchema] = useState("default");
  const [loading,     setLoading]     = useState(false);
  const [error,       setError]       = useState("");
  const [sqlQueries,  setSqlQueries]  = useState([]);

  const handleConnected = (d) => { setConnData(d); setScreen("input"); };

  const handleGenerate = async (formData) => {
    setLoading(true); setError(""); setSqlQueries([]);
    setColorSchema(formData.color_schema);
    try {
      const result = await generateDashboard(formData);
      setDashData(result);
      if (result.sql_queries) setSqlQueries(result.sql_queries);
      else if (result.charts) {
        const sqls = result.charts.filter(c => c.sql_query).map(c => ({ kpi:c.kpi, sql:c.sql_query }));
        setSqlQueries(sqls);
      }
      setScreen("dashboard");
    } catch (e) {
      setError(e.response?.data?.detail || "Dashboard generation failed. Please try again.");
    } finally { setLoading(false); }
  };

  const handleReset   = () => { setDashData(null); setScreen("input"); setError(""); setSqlQueries([]); };
  /* ← NEW: go back to connection screen from input */
  const handleBack    = () => { setConnData(null); setScreen("connect"); setError(""); setSqlQueries([]); };

  return (
    <>
      <div style={bgGrid}/>
      {error && (
        <div style={errToast}>
          <span>⚠️ {error}</span>
          <button onClick={() => setError("")} style={closeBtn}>✕</button>
        </div>
      )}

      {screen === "connect" && (
        <ConnectionScreen onConnected={handleConnected}/>
      )}
      {screen === "input" && connData && (
        <InputForm
          connectionData={connData}
          onSubmit={handleGenerate}
          loading={loading}
          sqlQueries={sqlQueries}
          onBack={handleBack}       /* ← pass back handler */
        />
      )}
      {screen === "dashboard" && dashData && (
        <DashboardScreen
          data={dashData}
          sessionId={connData?.session_id}
          colorSchema={colorSchema}
          onReset={handleReset}
          sqlQueries={sqlQueries}
        />
      )}
    </>
  );
}

/* Subtle pastel grid */
const bgGrid  = { position:"fixed", inset:0, backgroundImage:`linear-gradient(rgba(14,165,233,0.018) 1px,transparent 1px),linear-gradient(90deg,rgba(14,165,233,0.018) 1px,transparent 1px)`, backgroundSize:"52px 52px", pointerEvents:"none", zIndex:0 };
const errToast= { position:"fixed", top:20, left:"50%", transform:"translateX(-50%)", zIndex:1000, display:"flex", alignItems:"center", gap:12, padding:"12px 20px", background:"rgba(244,63,94,0.1)", border:"1px solid rgba(244,63,94,0.3)", borderRadius:12, color:"#fda4af", fontSize:14, backdropFilter:"blur(12px)", maxWidth:"90vw" };
const closeBtn= { background:"none", border:"none", color:"#fda4af", cursor:"pointer", fontSize:16, padding:"0 4px" };
